parameters.jsCode:
// Recuperer les donnees du webhook
const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationCode = body.automationCode;
const automationNom = body.automationNom;
const folderName = body.folderName || 'Client';
const existingFolderId = body.existingFolderId || null;

// Nom du dossier dans n8n : "[Client] NomEntreprise"
const n8nFolderName = `[Client] ${folderName}`;

return [{
  json: {
    tenantId,
    automationCode,
    automationNom,
    folderName: n8nFolderName,
    originalFolderName: folderName,
    existingFolderId
  }
}];

// Construire le workflow a creer pour ce client
const data = $input.first().json;
const clientName = data.originalFolderName;
const automationCode = data.automationCode;
const automationNom = data.automationNom;

// Workflow de base pour cette automatisation
const workflow = {
  name: `[${clientName}] ${automationNom}`,
  nodes: [
    {
      parameters: {
        rule: {
          interval: [{ field: 'hours', hoursInterval: 24 }]
        }
      },
      id: 'schedule-node',
      name: 'Declencheur',
      type: 'n8n-nodes-base.scheduleTrigger',
      typeVersion: 1.2,
      position: [250, 300]
    },
    {
      parameters: {
        jsCode: `// Automatisation: ${automationNom}\n// Client: ${clientName}\n// Code: ${automationCode}\n// Cree automatiquement par TalosPrimes\nconst now = new Date().toISOString();\nreturn [{ json: { client: '${clientName}', automation: '${automationCode}', timestamp: now, status: 'ok' } }];`
      },
      id: 'code-node',
      name: 'Traitement',
      type: 'n8n-nodes-base.code',
      typeVersion: 2,
      position: [470, 300]
    }
  ],
  connections: {
    'Declencheur': {
      main: [
        [{ node: 'Traitement', type: 'main', index: 0 }]
      ]
    }
  },
  settings: { executionOrder: 'v1' }
};

return [{ json: { ...data, workflow } }];

// Recuperer le resultat de la creation
const response = $input.first().json;
const workflowId = response.id || null;
const workflowName = response.name || null;
const data = $('02. Preparer donnees').first().json;
const existingFolderId = data.existingFolderId;

// Si on a un folderId existant et un workflowId, on peut deplacer
const canMove = !!(existingFolderId && workflowId);

return [{ json: {
  workflowId,
  workflowName,
  folderId: existingFolderId,
  folderName: data.folderName,
  tenantId: data.tenantId,
  automationCode: data.automationCode,
  automationNom: data.automationNom,
  canMove,
  status: workflowId ? 'workflow_cree' : 'erreur_creation'
} }];

const data = $('05. Verifier creation').first().json;
let movedToFolder = false;

try {
  const moveResult = $('07. Deplacer dans dossier').first();
  movedToFolder = moveResult && !moveResult.json?.message?.includes('error');
} catch {
  // pas de deplacement effectue
}

return [{ json: {
  success: !!data.workflowId,
  workflowId: data.workflowId,
  workflowName: data.workflowName,
  folderId: data.folderId,
  folderName: data.folderName,
  tenantId: data.tenantId,
  automationCode: data.automationCode,
  movedToFolder,
  workflowIds: data.workflowId ? [data.workflowId] : [],
  message: data.workflowId
    ? `Workflow "${data.workflowName}" cree avec succes${movedToFolder ? ` et deplace dans "${data.folderName}"` : ''}`
    : 'Erreur lors de la creation du workflow'
} }];
